mapper.select:
WITH my_organization AS ( SELECT orgn_id FROM esg.tb_hr_info WHERE hr_id = #{hrId} -- :hr_id AND use_yn = 'Y' LIMIT 1 ) SELECT CONCAT(r.write_year, '-', r.doc_type, '-', r.doc_no) AS id, r.key_content AS content, -- nullable json_build_object ( 'hrId', r.hr_id, 'name', r.hr_nm, 'jobTitle', r.jbrp_nm, 'orgName', r.orgn_nm, 'profileImageId', wi.file_id -- nullable ) AS writer, CASE WHEN COALESCE(r.receipt_dt, '') != '' THEN TO_TIMESTAMP(r.receipt_dt, 'YYYYMMDD')::TIMESTAMP ELSE NULL END AS receiptedAt, -- nullable CASE WHEN COALESCE(r.reply_dt, '') != '' THEN TO_TIMESTAMP(r.reply_dt, 'YYYYMMDD')::TIMESTAMP ELSE NULL END AS repliedAt, -- nullable CASE WHEN COALESCE(r.action_dt, '') != '' THEN TO_TIMESTAMP(r.action_dt, 'YYYYMMDD')::TIMESTAMP ELSE NULL END AS actionedAt, -- nullable r.action_content AS action, -- nullable r.remark, -- nullable CASE WHEN r.action_orgn_id IS NOT NULL THEN json_build_object( 'id', r.action_orgn_id, 'name', r.action_orgn_nm -- nullable ) ELSE NULL END AS actor, -- nullable r.created_at AS createdAt-- nullable FROM esg.tb_safety_health_info_register r LEFT JOIN esg.tb_sys_file wi ON wi.comp_id = r.comp_id AND wi.target_type = 'hrImg' AND wi.target_id = r.hr_id AND wi.del_yn = 'N' WHERE r.comp_id = #{compId} -- :comp_id /* :write_year; 특정 연도만 조회할 때 주석 해제 */
AND r.write_year = #{year} -- :write_year
/* :only_mine; 내가 관련된 상담만 조회시 주석 해제 */
AND (r.action_orgn_id = (SELECT orgn_id FROM my_organization) OR r.hr_id = #{hrId}) -- :hr_id
/* :only_undone; 미조치, 미회신건만 조회시 주석 해제 */ -- AND (COALESCE(r.action_dt, '') = '' OR COALESCE(r.reply_dt, '') = '') AND r.use_yn = 'Y' ORDER BY r.created_at DESC

mapper.update:
UPDATE esg.tb_safety_health_info_register
SET key_content = #{keyContent},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
  AND comp_id = #{compId}

UPDATE esg.tb_safety_health_info_register
SET use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}

UPDATE esg.tb_safety_health_info_register
SET action_content = #{actionContent},
    action_dt = #{actionDt},
    reply_dt = #{replyDt},
    updated_at = now(),
    updated_by = #{updatedBy},
    action_orgn_id = #{actionOrgnId},
    action_orgn_nm = (
        SELECT toi.orgn_nm
        FROM esg.tb_orgn_info toi
        WHERE toi.orgn_id = #{actionOrgnId}
        LIMIT 1
    )
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
